function Protect-MapleDbFixtureText([string]$Text,[string[]]$SensitiveValues){$safe=[string]$Text;foreach($value in @($SensitiveValues)){if(-not[string]::IsNullOrEmpty($value)){$safe=$safe.Replace($value,'[REDACTED]')}};$safe}
function Invoke-MapleDbFixtureProcess {
