  [pscustomobject]@{Kind='locked-db-only-synthetic-fixture';Executable=$false;Prefix=$prefix;Token=$token;Port=$Port;Container="$prefix-db";Network="$prefix-network";Volume="$prefix-volume";OwnershipLabel="farmrx.synthetic-dbfixture=$token";ImageRef='public.ecr.aws/supabase/postgres@sha256:9faa7279bcf1fd6834e65dc876b11e39cb53030bcb3d653beb7e5668200acbb5';ImageId='sha256:9faa7279bcf1fd6834e65dc876b11e39cb53030bcb3d653beb7e5668200acbb5';ContainsSecrets=$false;EphemeralPrivateInputs='synthetic password exists only in ownership-restricted env files; SQL stdin contains only current_setting lookup and neither secrets nor file contents are serialized as plan or evidence';HealthDeadlineSeconds=90;HealthPollMilliseconds=1000;PortRace='Loopback bind is released immediately before create; a release race remains.'}
}
function Invoke-MapleDbFixtureInitialization([string]$ContainerId,[string]$Prefix,[string]$PrivateExecEnvFilePath,[scriptblock]$CheckedInvoke){
 $sql="begin; do `$do`$ begin if not exists(select 1 from pg_roles where rolname='anon') then create role anon nologin; end if; if not exists(select 1 from pg_roles where rolname='authenticated') then create role authenticated nologin; end if; if not exists(select 1 from pg_roles where rolname='authenticator') then create role authenticator login; end if; end `$do`$; alter role anon nologin; alter role authenticated nologin; alter role authenticator login; do `$password_rotation`$ begin execute format('alter role authenticator password %L',current_setting('farmrx.private_password')); end `$password_rotation`$; create schema if not exists api; revoke all on schema api from public; create table if not exists api.fixture_proof(contract_hash text primary key not null,result text not null); revoke all on api.fixture_proof from public; grant anon to authenticator; grant authenticated to authenticator; grant usage on schema api to anon, authenticated; grant select on api.fixture_proof to anon, authenticated; insert into api.fixture_proof(contract_hash,result) values('$Prefix','fixture-ready') on conflict(contract_hash) do update set result=excluded.result; commit;"
 & $CheckedInvoke @('exec','--env-file',$PrivateExecEnvFilePath,'-i',$ContainerId,'psql','-X','-v','ON_ERROR_STOP=1','-U','postgres','-d','postgres','-f','-') 'fixture initialize' $sql|Out-Null
}
